#!/usr/bin/env python3
"""生成模块2的全部Jupyter notebook — 深度学习入门"""
import json, os

DIR = os.path.dirname(os.path.abspath(__file__))

def nb(cells):
    return {"nbformat":4,"nbformat_minor":5,"metadata":{"kernelspec":{"display_name":"Python 3","language":"python","name":"python3"},"language_info":{"name":"python","version":"3.10.0"}},"cells":cells}

def md(s):
    return {"cell_type":"markdown","metadata":{},"source":s if isinstance(s,list) else [s]}

def code(s):
    return {"cell_type":"code","metadata":{},"source":s if isinstance(s,list) else [s],"execution_count":None,"outputs":[]}

def write(name, cells):
    with open(os.path.join(DIR, name),'w',encoding='utf-8') as f:
        json.dump(nb(cells), f, ensure_ascii=False, indent=1)
    print(f"Written: {name}")

