code(["# ====== 纯Python实现梯度下降 ======\n","\n","# 初始化参数（随机值）\n","w = 0.0\n","b = 0.0\n","learning_rate = 0.00000001  # 学习率\n","n_epochs = 100              # 训练轮数\n","n_samples = len(freq)\n","\n","# 记录训练过程\n","losses = []\n","ws = []\n","bs = []\n","\n","for epoch in range(n_epochs):\n","    # 前向传播：计算预测值\n","    predictions = w * freq + b\n","    \n","    # 计算损失（均方误差）\n","    loss = np.mean((predictions - amplitude) ** 2)\n","    losses.append(loss)\n","    \n","    # 计算梯度（损失对参数的偏导数）\n","    dw = (2 / n_samples) * np.sum((predictions - amplitude) * freq)\n","    db = (2 / n_samples) * np.sum(predictions - amplitude)\n","    \n","    # 更新参数\n","    w = w - learning_rate * dw\n","    b = b - learning_rate * db\n","    \n","    ws.append(w)\n","    bs.append(b)\n","\n","print(f'训练结果: w = {w:.8f}, b = {b:.4f}')\n","print(f'真实值:   w = {true_w:.8f}, b = {true_b:.4f}')\n","print(f'最终损失: {losses[-1]:.6f}')"]),

