code(["import torch\n","import torch.nn as nn\n","import torch.optim as optim\n","\n","# 准备数据（转为PyTorch张量）\n","freq_tensor = torch.FloatTensor(freq).unsqueeze(1)   # shape: [50, 1]\n","amp_tensor = torch.FloatTensor(amplitude).unsqueeze(1) # shape: [50, 1]\n","\n","# 定义模型\n","model = nn.Linear(1, 1)  # 输入1维，输出1维\n","\n","# 定义损失函数和优化器\n","criterion = nn.MSELoss()\n","optimizer = optim.SGD(model.parameters(), lr=1e-7)\n","\n","# 训练\n","losses_torch = []\n","for epoch in range(100):\n","    # 前向传播\n","    predictions = model(freq_tensor)\n","    \n","    # 计算损失\n","    loss = criterion(predictions, amp_tensor)\n","    losses_torch.append(loss.item())\n","    \n","    # 反向传播（自动计算梯度！）\n","    optimizer.zero_grad()  # 清零梯度\n","    loss.backward()        # 计算梯度\n","    optimizer.step()       # 更新参数\n","\n","# 查看结果\n","w_learned = model.weight.item()\n","b_learned = model.bias.item()\n","print(f'PyTorch结果: w = {w_learned:.8f}, b = {b_learned:.4f}')\n","print(f'纯Python结果: w = {w:.8f}, b = {b:.4f}')\n","print(f'真实值:       w = {true_w:.8f}, b = {true_b:.4f}')"]),

